public int findMaxLength(int[] nums) {
    HashMap<Integer, Integer> counts = new HashMap<>();
    counts.put(0, -1);
    int max_len = 0, count = 0;
    for (int i = 0; i < nums.length; i++) {
        count += (nums[i] == 1) ? 1 : -1;
        if (counts.containsKey(count))
            max_len = Math.max(max_len, i - counts.get(count));
        else
            counts.put(count, i);
    }
    return max_len;
}
